import { useEffect, useState } from "react";
import Home from "../Home";

export default function ThreadSection({
                                          title = "Threads",
                                          width,
                                          showAddButton = false,
                                          onAddThread
                                      }) {
    const [threads, setThreads] = useState([]);
    const [hoveredId, setHoveredId] = useState(null);

    useEffect(() => {
        fetch("/api/threads")
            .then(r => r.json())
            .then(setThreads)
            .catch(() => setThreads([]));
    }, []);

    const boxHover = {
        transform: "translateY(-2px)",
        boxShadow: "0 6px 16px rgba(0,0,0,0.25)",
        backgroundColor: "#cac7c7"
    };

    return (
        <div style={{ width, display: "flex", flexDirection: "column" }}>
            {showAddButton && (
                <button onClick={onAddThread}>
                    Add Thread
                </button>
            )}

            <h3>{title}</h3>

            {threads.map(thread => (
                <div
                    key={thread.id}
                    style={{
                        padding: "12px",
                        cursor: "pointer",
                        backgroundColor: "#605f5f",
                        transition: "0.15s",
                        ...(hoveredId === thread.id ? boxHover : {})
                    }}
                    onMouseEnter={() => setHoveredId(thread.id)}
                    onMouseLeave={() => setHoveredId(null)}
                    onClick={() => {
                        window.location.hash = `#/thread/${thread.id}`;
                    }}
                >
                    <div style={{ fontWeight: 600 }}>{thread.title}</div>
                    <div style={{ fontSize: "0.75rem", opacity: 0.7 }}>
                        {thread.published &&
                            new Date(thread.published).toLocaleDateString()}
                        {thread.author && ` · ${thread.author}`}
                    </div>
                </div>
            ))}
        </div>
    );
}
